// console_putchar via SBI ecall — the canonical pattern:
//   a0 = character byte
//   a6 = 0 (fid for console_putchar)
//   a7 = 1 (EID for legacy console putchar)
//   ecall  transfers to M-mode; OpenSBI handles the actual UART write
void console_putchar(int c) {
    asm volatile("li a7, 1\n"
                 "li a6, 0\n"
                 "mv a0, %0\n"
                 "ecall"
                 :
                 : "r"(c)
                 : "a0", "a6", "a7", "memory");
}
